use std::collections::HashMap;
use swc_ecma_ast::*;
use serde::Serialize;
use swc_ecma_visit::Visit;

#[derive(Serialize)]
pub struct FunctionRecordResult {
    pub local_name: String,
    pub start: u32,
    pub end: u32,
}

#[derive(Serialize)]
pub struct FunctionGraphResult {
    pub functions_by_local_name: HashMap<String, FunctionRecordResult>,
    pub exports_by_name: HashMap<String, String>,
}

struct FunctionGraphExtractor {
    pub result: FunctionGraphResult,
    pub anonymous_count: u32,
}

impl FunctionGraphExtractor {
    fn new() -> Self {
        Self {
            result: FunctionGraphResult {
                functions_by_local_name: HashMap::new(),
                exports_by_name: HashMap::new(),
            },
            anonymous_count: 0,
        }
    }

    fn next_anon_name(&mut self) -> String {
        let name = format!("__default_export_{}", self.anonymous_count);
        self.anonymous_count += 1;
        name
    }

    fn add_function(&mut self, local_name: String, start: u32, end: u32) {
        self.result.functions_by_local_name.insert(
            local_name.clone(),
            FunctionRecordResult { local_name, start, end },
        );
    }
}

impl Visit for FunctionGraphExtractor {
    fn visit_module_item(&mut self, item: &ModuleItem) {
        match item {
            ModuleItem::ModuleDecl(decl) => match decl {
                ModuleDecl::ExportDecl(export) => {
                    match &export.decl {
                        Decl::Fn(fn_decl) => {
                            let name = fn_decl.ident.sym.to_string();
                            self.add_function(name.clone(), fn_decl.function.span.lo.0 - 1, fn_decl.function.span.hi.0 - 1);
                            self.result.exports_by_name.insert(name.clone(), name);
                        }
                        Decl::Var(var_decl) => {
                            for decl in &var_decl.decls {
                                if let Pat::Ident(ident) = &decl.name {
                                    if let Some(init) = &decl.init {
                                        if init.is_arrow() || init.is_fn_expr() {
                                            let name = ident.id.sym.to_string();
                                            self.add_function(name.clone(), init.span_lo().0 - 1, init.span_hi().0 - 1);
                                            self.result.exports_by_name.insert(name.clone(), name);
                                        }
                                    }
                                }
                            }
                        }
                        _ => {}
                    }
                }
                ModuleDecl::ExportDefaultDecl(export) => {
                    match &export.decl {
                        DefaultDecl::Fn(fn_expr) => {
                            let name = if let Some(ident) = &fn_expr.ident {
                                ident.sym.to_string()
                            } else {
                                self.next_anon_name()
                            };
                            self.add_function(name.clone(), fn_expr.function.span.lo.0 - 1, fn_expr.function.span.hi.0 - 1);
                            self.result.exports_by_name.insert("default".to_string(), name);
                        }
                        _ => {}
                    }
                }
                ModuleDecl::ExportDefaultExpr(export) => {
                    if let Expr::Ident(ident) = &*export.expr {
                        self.result.exports_by_name.insert("default".to_string(), ident.sym.to_string());
                    } else if export.expr.is_arrow() || export.expr.is_fn_expr() {
                        let name = self.next_anon_name();
                        self.add_function(name.clone(), export.expr.span_lo().0 - 1, export.expr.span_hi().0 - 1);
                        self.result.exports_by_name.insert("default".to_string(), name);
                    }
                }
                ModuleDecl::ExportNamed(export) => {
                    if export.src.is_none() {
                        for specifier in &export.specifiers {
                            if let ExportSpecifier::Named(named) = specifier {
                                let orig = match &named.orig {
                                    ModuleExportName::Ident(ident) => ident.sym.to_string(),
                                    ModuleExportName::Str(s) => s.value.to_string(),
                                };
                                let export_name = if let Some(exported) = &named.exported {
                                    match exported {
                                        ModuleExportName::Ident(ident) => ident.sym.to_string(),
                                        ModuleExportName::Str(s) => s.value.to_string(),
                                    }
                                } else {
                                    orig.clone()
                                };
                                self.result.exports_by_name.insert(export_name, orig);
                            }
                        }
                    }
                }
                _ => {}
            },
            ModuleItem::Stmt(stmt) => match stmt {
                Stmt::Decl(Decl::Fn(fn_decl)) => {
                    let name = fn_decl.ident.sym.to_string();
                    self.add_function(name.clone(), fn_decl.function.span.lo.0 - 1, fn_decl.function.span.hi.0 - 1);
                }
                Stmt::Decl(Decl::Var(var_decl)) => {
                    for decl in &var_decl.decls {
                        if let Pat::Ident(ident) = &decl.name {
                            if let Some(init) = &decl.init {
                                if init.is_arrow() || init.is_fn_expr() {
                                    let name = ident.id.sym.to_string();
                                    self.add_function(name.clone(), init.span_lo().0 - 1, init.span_hi().0 - 1);
                                }
                            }
                        }
                    }
                }
                _ => {}
            },
        }
    }
}
